/* CMP_INDX - arithmetic */
static void inst_CMP_INDX(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t ptr = (uint8_t)(inst->zp + cpu->registers[REG_X]);
    uint8_t lo = mos6502_read_byte(cpu, (uint16_t)ptr);
    uint8_t hi = mos6502_read_byte(cpu, (uint16_t)((uint8_t)(ptr + 1u)));
    uint16_t addr = (uint16_t)(((uint16_t)hi << 8) | (uint16_t)lo);
    uint8_t lhs = cpu->registers[REG_A];
    uint8_t rhs = mos6502_read_byte(cpu, addr);
    uint16_t diff = (uint16_t)lhs - (uint16_t)rhs;
    cpu->flags.C = (lhs >= rhs);
    cpu->flags.Z = (((uint8_t)diff) == 0u);
    cpu->flags.N = ((((uint8_t)diff) & 0x80u) != 0u);
}

