/* SBC_INDX - arithmetic */
static void inst_SBC_INDX(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t ptr = (uint8_t)(inst->zp + cpu->registers[REG_X]);
    uint8_t lo = mos6502_read_byte(cpu, (uint16_t)ptr);
    uint8_t hi = mos6502_read_byte(cpu, (uint16_t)((uint8_t)(ptr + 1u)));
    uint16_t addr = (uint16_t)(((uint16_t)hi << 8) | (uint16_t)lo);
    uint8_t m = mos6502_read_byte(cpu, addr);
    uint8_t a = cpu->registers[REG_A];
    uint8_t carry_in = cpu->flags.C ? 1u : 0u;
    uint16_t sub = (uint16_t)m + (uint16_t)(1u - carry_in);
    uint16_t wide = (uint16_t)a - sub;
    uint8_t r = (uint8_t)wide;
    cpu->registers[REG_A] = r;
    cpu->flags.C = ((uint16_t)a >= sub);
    cpu->flags.Z = (r == 0u);
    cpu->flags.N = ((r & 0x80u) != 0u);
    cpu->flags.V = ((((a ^ m) & (a ^ r)) & 0x80u) != 0u);
}

